findings.codeql_raw_query:
/**
 * @name Buffer writeability missing check in cipher operations
 * @description Cipher operations using from_buffer may not check buffer writeability before writing
 * @kind path-problem
 * @problem.severity error
 * @id py/buffer-writeability-check
 * @tags security
 *        external/cwe/cwe-754
 */

import python
import semmle.python.dataflow.new.DataFlow
import semmle.python.dataflow.new.TaintTracking
import semmle.python.dataflow.new.RemoteFlowSources
import semmle.python.Concepts

module BufferWriteConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // Look for from_buffer calls in cipher contexts
    exists(Call c |
      c.getFunc().(Attribute).getName() = "from_buffer"
      and c.getLocation().getFile().getRelativePath().matches("%cipher%")
      and sink = DataFlow::exprNode(c.getArg(0))
    )
  }
}

module BufferWriteFlow = TaintTracking::Global<BufferWriteConfig>;
import BufferWriteFlow::PathGraph

from BufferWriteFlow::PathNode source, BufferWriteFlow::PathNode sink
where BufferWriteFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Untrusted data flows into buffer write operation at $@.", source.getNode(), "user input"
